import React from "react";
import "./App.css";
import { Toaster } from "sonner";

import { Navbar } from "./lib/site/Navbar";
import { Hero } from "./lib/site/Hero";
import { Trust } from "./lib/site/Trust";
import { Marquee } from "./lib/site/Marquee";
import { Services } from "./lib/site/Services";
import { FeaturedWork } from "./lib/site/FeaturedWork";
import { WhySuryanova } from "./lib/site/WhySuryanova";
import { Process } from "./lib/site/Process";
import { Testimonials } from "./lib/site/Testimonials";
import { About } from "./lib/site/About";
import { Contact } from "./lib/site/Contact";
import { Footer } from "./lib/site/Footer";
import { WhatsAppButton } from "./lib/site/WhatsAppButton";
import { Loader } from "./lib/site/Loader";

function App() {
  return (
    <div className="App" data-testid="app-root">
      <Loader />
      <Navbar />

      <main>
        <Hero />
        <Trust />
        <Marquee />
        <Services />
        <FeaturedWork />
        <WhySuryanova />
        <Process />
        <Testimonials />
        <About />
        <Contact />
      </main>

      <Footer />
      <WhatsAppButton />
      <Toaster position="bottom-center" richColors closeButton />
    </div>
  );
}

export default App;
